var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"찾았다.","JPN":"見つけた。","ENG":"Found it.","TWN":"找到了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……이미 숨이 끊어져 있어요.","JPN":"……すでに息絶えています。","ENG":"...The person was already dead.","TWN":"……已經斷氣了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무언가에 여러 번 베인 흔적? 침식체 짓인가?","JPN":"何かに何回も斬られた跡？　侵食体の仕業なのか？","ENG":"Looks like multiple slash wounds. Was it done by a C.O.?","TWN":"被什麼東西多次割傷的痕跡？是侵蝕體幹的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"일단, 시신을 수습하고 나가는 건 어때?","JPN":"とりあえず、死体を収拾して出たらどう？","ENG":"How about retrieving the body and getting out of there?","TWN":"要不先把屍體收拾一下再走？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"침식 지대에 오래 있어봤자 좋을 게 없을 것 같은데.","JPN":"侵食地帯に長居するのは良くないと思うわよ。","ENG":"Nothing good comes from staying in a Corrupted Area for too long.","TWN":"在侵蝕地帶待久了，恐怕不會有什麼好事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"멍멍이는 CRF 소모가 심하잖아.","JPN":"ワンちゃんはCRFの消耗が激しいじゃない。","ENG":"You burn through CRF fast, Puppy.","TWN":"狗狗的CRF消耗很大啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 정도는 아직 거뜬해요.","JPN":"このくらいはまだ何ともないです。","ENG":"This much is nothing.","TWN":"這種程度我還撐得住。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"요즘 이터니움값이 워낙 많이 올라야지.","JPN":"最近はエタニウムが高すぎるわ。","ENG":"You know, Eternium prices have skyrocketed lately.","TWN":"最近永恆之金的價格漲得真厲害。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"네 CRF를 충전하는 비용도 생각해.","JPN":"あなたのCRFをチャージする費用も考えなさい。","ENG":"Think about how much it'll cost to recharge your CRF.","TWN":"也要考慮到補充CRF的費用。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……나갈게요.","JPN":"……出ますね。","ENG":"...Fine, I'll leave.","TWN":"……我出去吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"길을 못 찾겠어요.","JPN":"道がわからないです。","ENG":"I can't find my way out.","TWN":"我找不到路。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"보통은 바람 냄새로 찾을 수 있는데…….","JPN":"普段は風の匂いで探せるのに……","ENG":"Normally, I rely on the scent of the wind to track my path...","TWN":"通常可以透過風的氣味找到……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"이상하네. 내 눈으로도 위치를 추적할 수 없어.","JPN":"おかしいわね。私の目でも位置を追跡できないわ。","ENG":"That's odd. I can't pinpoint your location either.","TWN":"奇怪，連我都無法用眼睛追蹤到位置。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"마치 공간이 뒤틀린 것 같은 느낌이랄까?","JPN":"まるで空間が歪曲しているような感じよ。","ENG":"It feels like space itself is distorting.","TWN":"感覺就像空間扭曲了一樣？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"음, 어쩔 수 없겠네요.","JPN":"うーん、仕方ないですね。","ENG":"Well, no choice then.","TWN":"嗯，沒辦法了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"의뢰인한테 구조대를 불러달라고 해야겠어요.","JPN":"依頼人に救助隊を呼んでもらうしかなさそうです。","ENG":"I'll ask the client to call a rescue team.","TWN":"得讓委託人叫救援隊過來才行。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"구조를 기다리면서 겸사겸사 침식체를 잡는 거죠.","JPN":"救助を待ちながら、ついでに侵食体をやっつけますよ。","ENG":"Might as well hunt some C.O.s while I wait.","TWN":"等待救援的同時順便處理侵蝕體。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"기왕이면 이터니움이 덕지덕지 박힌 침식체 위주로.","JPN":"どうせならエタニウムががっつり刺さっている侵食体メインで。","ENG":"Preferably ones covered with Eternium.","TWN":"既然如此，就以鑲滿永恆之金的侵蝕體為主吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"어차피 그 이터니움 전부 팔아봤자 네 CRF를 충전하면…….","JPN":"どうせそのエタニウムを全部売っても、あなたのCRFをチャージしたら……","ENG":"Even if you sell all that Eternium, once you recharge your CRF–","TWN":"就算把那些永恆之金全部賣掉，補充到你的CRF上……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"잠시만요.","JPN":"待ってください。","ENG":"Hold on.","TWN":"等下。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무슨 소리가 들려요.","JPN":"なんか音が聞こえます。","ENG":"I hear something.","TWN":"什麼聲音？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NUN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"성황청? 성황청이 여긴 왜……?","JPN":"聖皇庁？　どうして聖皇庁がここに……？","ENG":"Holy Curia? What's the Holy Curia doing here...?","TWN":"聖皇廳？聖皇廳怎麼會在這裡……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"잠깐…… 수녀가 책을 들고 있어요.","JPN":"待って……シスターが持っている本。","ENG":"Wait... that nun is holding a book.","TWN":"等一下……修女手裡拿著的書。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"책에서 침식체 냄새가 나요.","JPN":"その本から侵食体の匂いがします。","ENG":"And that book reeks of C.O.","TWN":"書上有侵蝕體的氣味。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};